@startuml
skinparam ClassDiagram labelStyle "C"
skinparam Interface labelStyle "I"

class Client {
    label "C"
    label "Client"
}

class Command {
    label "I"
    label "Command"
    method execute()
}

class ConcreteCommand {
    label "C"
    label "ConcreteCommand"
}

class Receiver {
    label "C"
    label "Receiver"
    method action()
}

class Invoker {
    label "C"
    label "Invoker"
}

Client --> Receiver
Client --> ConcreteCommand
ConcreteCommand --> Receiver
ConcreteCommand ..> Command : implements
Invoker ..> Command : uses

note right of ConcreteCommand
    Receiver -> action()
@enduml
